create table if not exists public.ai_pricing_metadata (id uuid primary key default gen_random_uuid(), provider text not null, model text not null, effective_date date, currency text not null default 'USD', input_unit_cost numeric not null default 0, output_unit_cost numeric not null default 0, tool_costs jsonb not null default '{}'::jsonb, last_verified_at timestamptz, status text not null default 'UNVERIFIED_CONFIG', created_at timestamptz not null default now(), unique(provider,model,effective_date));
create table if not exists public.ai_usage_ledger (id uuid primary key default gen_random_uuid(), account_id uuid not null references public.accounts(id) on delete cascade, workspace_id uuid, mission_id uuid, provider text not null, model text not null, model_tier text not null, input_tokens integer not null default 0, output_tokens integer not null default 0, tool_cost numeric not null default 0, estimated_cost numeric not null default 0, actual_cost numeric, currency text not null default 'USD', request_fingerprint text not null, created_at timestamptz not null default now());
alter table public.ai_pricing_metadata enable row level security; alter table public.ai_usage_ledger enable row level security;
revoke all on public.ai_pricing_metadata from anon, authenticated; revoke all on public.ai_usage_ledger from anon, authenticated;
create policy ai_usage_owner_read on public.ai_usage_ledger for select to authenticated using (account_id=auth.uid());
comment on table public.ai_usage_ledger is 'Server-written cost metadata only. Never stores raw prompts or model responses.';
